import { comparePreparedFunctionResults } from "./bundle-runtime.result-comparator.js";

export const BUNDLE_PUBLICATION_PROMOTION_EVIDENCE_SCHEMA = "bundle_publication_promotion_evidence.v1";

export class BundlePublicationPromotionEvidenceError extends Error {
  constructor(message) {
    super(message);
    this.name = "BundlePublicationPromotionEvidenceError";
  }
}

// Evidence is generated by a server-side fixture provider. This validator never
// accepts an identifier, cart selection, or operation result from an HTTP client.
export function assertPublicationPromotionEvidence(evidence, expected) {
  if (!isPlainObject(evidence)) fail("promotion evidence must be an object");
  if (evidence.schema_version !== BUNDLE_PUBLICATION_PROMOTION_EVIDENCE_SCHEMA) {
    fail("promotion evidence schema is unsupported");
  }
  assertExact(evidence.bundle_definition_id, expected.bundle_definition_id, "bundle_definition_id");
  assertExact(evidence.revision_id, expected.revision_id, "revision_id");
  assertExact(evidence.snapshot_checksum, expected.snapshot_checksum, "snapshot_checksum");
  if (typeof evidence.fixture_set_id !== "string" || evidence.fixture_set_id.trim() === "") {
    fail("promotion evidence fixture_set_id is required");
  }
  if (!Array.isArray(evidence.fixtures) || evidence.fixtures.length === 0) {
    fail("promotion evidence requires at least one fixture");
  }

  const fixtureIds = new Set();
  const comparisons = evidence.fixtures.map((fixture, index) => {
    if (!isPlainObject(fixture)) fail(`promotion fixture ${index} must be an object`);
    if (typeof fixture.fixture_id !== "string" || fixture.fixture_id.trim() === "") {
      fail(`promotion fixture ${index} fixture_id is required`);
    }
    if (fixtureIds.has(fixture.fixture_id)) fail(`promotion fixture_id "${fixture.fixture_id}" is duplicated`);
    fixtureIds.add(fixture.fixture_id);
    if (!isPlainObject(fixture.hardcoded_result) || !isPlainObject(fixture.candidate_result)) {
      fail(`promotion fixture "${fixture.fixture_id}" results must be objects`);
    }
    const comparison = comparePreparedFunctionResults(fixture.hardcoded_result, fixture.candidate_result);
    if (!comparison.match || comparison.differences.length > 0) {
      fail(`promotion fixture "${fixture.fixture_id}" does not have exact parity`);
    }
    return { fixture_id: fixture.fixture_id, comparison };
  });

  return {
    fixture_set_id: evidence.fixture_set_id,
    fixture_count: comparisons.length,
    comparisons,
  };
}

function assertExact(actual, expected, field) {
  if (typeof actual !== "string" || actual !== expected) {
    fail(`promotion evidence ${field} does not match the publication target`);
  }
}

function fail(message) {
  throw new BundlePublicationPromotionEvidenceError(message);
}

function isPlainObject(value) {
  return value != null && typeof value === "object" && !Array.isArray(value);
}
